const formBaseUrl = 'https://n8n.oi.destination.one/form/a603e13b-9560-452e-964a-4f48f5aefe3c';

return items.map(item => {
  const j = item.json;

  return {
    json: {
      ...j,
      reviewUrl: `${formBaseUrl}?batch_id=${encodeURIComponent(j.batch_id)}`
    }
  };
});

function pickRelevantTexts(texts) {
  if (!Array.isArray(texts)) return [];

  const order = ['teaser', 'details', 'WeitereInfos'];

  return texts
    .filter(t => ['details', 'teaser', 'WeitereInfos'].includes(t?.rel))
    .filter(t => t?.type === 'text/plain')
    .map(t => ({
      rel: t.rel ?? '',
      type: t.type ?? '',
      value: (t.value ?? '').trim()
    }))
    .filter(t => t.value)
    .sort((a, b) => {
      const indexA = order.indexOf(a.rel);
      const indexB = order.indexOf(b.rel);

      const safeIndexA = indexA === -1 ? Number.MAX_SAFE_INTEGER : indexA;
      const safeIndexB = indexB === -1 ? Number.MAX_SAFE_INTEGER : indexB;

      return safeIndexA - safeIndexB;
    });
}

function normalizeValueArray(arr) {
  if (!Array.isArray(arr)) return [];

  return arr
    .map(item => {
      if (typeof item === 'string') return item;
      if (item?.value) return item.value;
      if (item?.name) return item.name;
      return '';
    })
    .filter(Boolean);
}

function normalizeAttributes(attributes) {
  if (!Array.isArray(attributes)) return [];

  return attributes
    .map(attr => ({
      key: attr?.key ?? '',
      value: attr?.value ?? ''
    }))
    .filter(attr => attr.key || attr.value);
}

function getAddressByRel(addresses, rel) {
  if (!Array.isArray(addresses)) return null;
  return addresses.find(a => a?.rel === rel) ?? null;
}

function pickAuthorName(addresses) {
  const author = getAddressByRel(addresses, 'author');
  return author?.name ?? '';
}

function pickOrganisationName(addresses) {
  const org = getAddressByRel(addresses, 'organisation');
  return org?.name ?? '';
}

function buildCombinedText(texts) {
  if (!Array.isArray(texts)) return '';

  return texts
    .map(t => `[${t.rel}] ${t.value}`)
    .join('\n\n')
    .trim();
}

function pickPrimaryArea(areas) {
  const normalized = normalizeValueArray(areas);

  const allowedAreas = [
    'Erzgebirge',
    'Leipzig',
    'Leipzig Region',
    'Oberlausitz',
    'Vogtland',
    'Chemnitz.Zwickau.Region.',
    'Sächsische Schweiz',
    'Dresden Elbland',
    'Dresden',
    'Chemnitz'
  ];

  for (const area of normalized) {
    if (allowedAreas.includes(area)) {
      return area;
    }
  }

  for (const area of normalized) {
    if (area.includes('Erzgebirge')) return 'Erzgebirge';
    if (area.includes('Vogtland')) return 'Vogtland';
    if (area.includes('Leipzig Region')) return 'Leipzig Region';
    if (area.includes('Leipzig')) return 'Leipzig';
    if (area.includes('Oberlausitz')) return 'Oberlausitz';
    if (area.includes('Sächsische Schweiz')) return 'Sächsische Schweiz';
    if (area.includes('Dresden Elbland')) return 'Dresden Elbland';
    if (area.includes('Dresden')) return 'Dresden';
    if (area.includes('Chemnitz.Zwickau.Region.')) return 'Chemnitz.Zwickau.Region.';
    if (area.includes('Chemnitz')) return 'Chemnitz';
  }

  return '';
}

return items.map(item => {
  const j = item.json ?? {};

  const reducedTexts = pickRelevantTexts(j.texts);
  const normalizedAreas = normalizeValueArray(j.areas);

  return {
    json: {
      id: j.id ?? '',
      global_id: j.global_id ?? '',
      title: j.title ?? '',
      type: j.type ?? '',
      country: j.country ?? '',
      city: j.city ?? '',
      zip: j.zip ?? '',
      street: j.street ?? '',
      contactEmail: j.email ?? '',
      web: j.web ?? '',
      created: j.created ?? '',
      changed: j.changed ?? '',

      authorName: pickAuthorName(j.addresses),
      organisationName: pickOrganisationName(j.addresses),

      categories: normalizeValueArray(j.categories),
      areas: normalizedAreas,
      primaryArea: pickPrimaryArea(j.areas),
      features: normalizeValueArray(j.features),
      attributes: normalizeAttributes(j.attributes),

      texts: reducedTexts,
      combinedText: buildCombinedText(reducedTexts)
    }
  };
});

if (!items.length) {
  return [];
}

const first = items[0].json;
const count = items.length;
const reviewUrl = first.reviewUrl ?? '';

return [
  {
    json: {
      to: first.Email_Datenpflegender_Region ?? '',
      subject: `EMPCO-Prüfung: ${count} Datensätze zur Freigabe`,
      body:
`Hallo ${first.Name_Datenpflegender_Region ?? ''},

es wurden ${count} Datensätze gefunden, die potenziell gegen die EMPCO-Richtlinie verstoßen könnten.

Bitte prüfe diese über den folgenden Link:
${reviewUrl}

Viele Grüße
Euer Digitalteam`
    }
  }
];
